# Time:  O(l * nlogn)
# Space: O(1)

# sort
class Solution(object):
    def phonePrefix(self, numbers):
        """
        :type numbers: List[str]
        :rtype: bool
        """
        numbers.sort()
        return all(not numbers[i+1].startswith(numbers[i]) for i in xrange(len(numbers)-1))


